if (! function_exists('dice_roller')) {
    function dice_roller($dice_type = null, $count = null, $advantage = null, $disadvantage = null, $success_threshold = null, $modifier = null, $seed = null)
    {
        $diceType = isset($dice_type) ? (string)$dice_type : 'd20';
        $count = isset($count) ? max(1, min(100, (int)$count)) : 1;
        $adv = isset($advantage) ? (bool)$advantage : false;
        $dis = isset($disadvantage) ? (bool)$disadvantage : false;
        $successThresh = isset($success_threshold) ? (int)$success_threshold : null;
        $mod = isset($modifier) ? (int)$modifier : 0;
        $seed = isset($seed) && $seed > 0 ? (int)$seed : 0;

        // Validate dice type
        $validDice = ['d4'=>4,'d6'=>6,'d8'=>8,'d10'=>10,'d12'=>12,'d20'=>20,'d100'=>100];
        $diceKey = strtolower($diceType);
        if (!isset($validDice[$diceKey])) {
            return json_encode(['error' => "Invalid dice type: {$diceType}. Valid: d4,d6,d8,d10,d12,d20,d100"]);
        }
        $sides = $validDice[$diceKey];

        // Seed if provided
        if ($seed > 0) {
            srand($seed);
        }

        // Helper: roll a single die
        $rollDie = function() use ($sides) {
            return rand(1, $sides);
        };

        $rolls = [];
        $total = 0;

        if ($adv || $dis) {
            // Advantage/disadvantage only meaningful for single die
            $roll1 = $rollDie();
            $roll2 = $rollDie();
            $final = $adv ? max($roll1, $roll2) : min($roll1, $roll2);
            $rolls = [$roll1, $roll2];
            $total = $final + $mod;
            
            return json_encode([
                'dice' => $diceKey,
                'count' => 1,
                'rolls' => $rolls,
                'final' => $final,
                'modifier' => $mod,
                'total' => $total,
                'advantage' => $adv,
                'disadvantage' => $dis,
                'natural_20' => $final === 20 && $diceKey === 'd20',
                'natural_1' => $final === 1 && $diceKey === 'd20',
                'successes' => $successThresh !== null ? ($final >= $successThresh ? 1 : 0) : null,
                'success_threshold' => $successThresh,
            ]);
        }

        // Normal rolling
        $successes = 0;
        for ($i = 0; $i < $count; $i++) {
            $r = $rollDie();
            $rolls[] = $r;
            $total += $r;
            if ($successThresh !== null && $r >= $successThresh) {
                $successes++;
            }
        }
        $total += $mod;

        // Calculate statistics
        $min = min($rolls);
        $max = max($rolls);
        $avg = array_sum($rolls) / count($rolls);

        $crit20 = $diceKey === 'd20' ? count(array_filter($rolls, fn($r) => $r === 20)) : 0;
        $crit1 = $diceKey === 'd20' ? count(array_filter($rolls, fn($r) => $r === 1)) : 0;

        return json_encode([
            'dice' => $diceKey,
            'count' => $count,
            'sides' => $sides,
            'rolls' => $rolls,
            'sum_raw' => array_sum($rolls),
            'modifier' => $mod,
            'total' => $total,
            'min' => $min,
            'max' => $max,
            'average' => round($avg, 2),
            'advantage' => false,
            'disadvantage' => false,
            'natural_20s' => $crit20,
            'natural_1s' => $crit1,
            'successes' => $successThresh !== null ? $successes : null,
            'success_threshold' => $successThresh,
            'success_rate' => $successThresh !== null && $count > 0 ? round($successes / $count * 100, 1) : null,
        ]);
